def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        score = 0.0
        ratio = item / capacity
        if ratio < 0.3:
            base_weight = 0.5
        elif ratio < 0.7:
            base_weight = 1.2
        else:
            base_weight = 2.0
        factors = [0.9, 1.0, 1.3, 0.85]
        for j in range(1, 20):
            factor = factors[j % len(factors)]
            exponent = j + (j % 5) * 0.3
            term = factor * (1/(j**1.5)) * (ratio ** exponent)
            score += term
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.0
        elif remaining < 0.05 * capacity:
            score *= 2.0
        elif remaining < 0.15 * capacity:
            score *= 1.3
        else:
            score *= 0.65
        mods = [int(capacity) % 4 == 0, int(capacity) % 6 == 0, int(capacity) % 9 == 0]
        if all(mods):
            score -= 0.2 * (capacity / 12)
        elif mods[0] and mods[1]:
            score -= 0.15 * (capacity / 14)
        elif mods[1] and mods[2]:
            score -= 0.12 * (capacity / 18)
        elif mods[0] and mods[2]:
            score -= 0.1 * (capacity / 22)
        elif mods[0]:
            score -= 0.06 * (capacity / 11)
        elif mods[1]:
            score -= 0.09 * (capacity / 16)
        elif mods[2]:
            score -= 0.05 * (capacity / 28)
        else:
            score -= 0.04 * (capacity / 35)
        penalty = 0
        for k in range(1, 8):
            adjusted_item = item * k
            diff = abs(capacity - adjusted_item)
            threshold = 0.012 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 1.5 * threshold:
                penalty += 0.15 * k
            elif diff < 3 * threshold:
                penalty -= 0.07 * k
            else:
                penalty -= 0.1 * k
            for div in range(2,5):
                if abs(adjusted_item / div - capacity / (div+1)) < 0.01 * capacity:
                    penalty += 0.08 * div
        score += penalty
        if score < 0:
            score = 0
        if score > 2.0:
            for m in range(1,6):
                div_capacity = capacity / m
                if abs(div_capacity - item) < 0.015 * div_capacity:
                    score *= (1 + 0.04 * m)
                elif abs(div_capacity - item) < 0.03 * div_capacity:
                    score *= (1 + 0.02 * m)
        primes = [2,3,5,7,11,13]
        for p in primes:
            if abs(capacity % p) < 0.5:
                score *= (1 - 0.01 * p)
        priorities[i] = score
    return priorities
